import sympy
from sympy.functions.combinatorial.numbers import stirling
def a(n):
    res = 0
    for k in range(1, (n + 1) // 2 + 1):
        res += sympy.factorial(k) * stirling(n - k + 1, k, kind=2) * (2 ** (n - 2 * k + 1))
    return res
print([a(n) for n in range(1, 21)])

